onClick:
{{
  (async () => {
    await storeValue('selectedModus', 'Später'); 
    const jetzigerZeitstempel = moment().format('DD.MM.YYYY HH:mm');

    try {
      // 1. Eintrag im Log-Sheet "Bewaesserung" speichern
      await Bewaesserung_Speichern.run({
        ventilName: appsmith.store.activeVentil,
        programm: appsmith.store.selectedProg,
        modus: 'Zeit',
        zeitstempel: jetzigerZeitstempel,
        stammdaten: Stammdaten.data
      });

      // 2. Bestehende Zeile in "Stammdaten" aktualisieren (TRUE löschen)
      await Stammdaten_Update.run();

      // 3. Modal schließen & Daten neu laden
      closeModal('Modal_Programm');
      Bewaesserung_Lesen.run();
      Stammdaten.run(); // Lädt auch die Stammdaten neu

    } catch (e) {
      showAlert("Fehler beim Speichern: " + e.message, "error");
    }
  })()
}}
